import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Cart = () => {
    const [cart, setCart] = useState([]);
    const [totalPrice, setTotalPrice] = useState(0);
    const customerId = sessionStorage.getItem("customerid");
    const navigate = useNavigate();

    const fetchCart = () => {
        if (customerId) {
            axios.post("http://localhost:3001/customer/viewcart", { customerId })
                .then(response => {
                    if (Array.isArray(response.data)) {
                        setCart(response.data);
                        // Calculate total price
                        const total = response.data.reduce((acc, item) => {
                            if (!item.productId) return acc;
                            return acc + (item.productId.price * item.quantity);
                        }, 0);
                        setTotalPrice(total);
                    } else {
                        setCart([]);
                        setTotalPrice(0);
                    }

                })
                .catch(err => {
                    console.error("Error fetching cart:", err);
                    alert("Could not fetch cart items.");
                });
        }
    };

    useEffect(() => {
        fetchCart();
    }, [customerId]);

    const handleIncrement = (productId) => {
        axios.post("http://localhost:3001/customer/addtocart", { customerId, productId })
            .then(response => {
                if (response.data.status === "success") {
                    fetchCart(); // Refresh cart
                } else {
                    alert(response.data.message || "Failed to update quantity.");
                }
            })
            .catch(err => {
                console.error("Error incrementing cart:", err);
                alert("An error occurred while updating quantity.");
            });
    };

    const handleDecrement = (productId) => {
        axios.post("http://localhost:3001/customer/decrementcartitem", { customerId, productId })
            .then(response => {
                if (response.data.status === "success") {
                    fetchCart(); // Refresh cart
                } else {
                    alert(response.data.message || "Failed to update quantity.");
                }
            })
            .catch(err => {
                console.error("Error decrementing cart:", err);
                alert("An error occurred while updating quantity.");
            });
    };

    const handleRemoveFromCart = (productId) => {
        axios.post("http://localhost:3001/customer/removefromcart", { customerId, productId })
            .then(response => {
                if (response.data.status === "success") {
                    alert("Product removed from cart.");
                    fetchCart(); // Refresh cart
                } else {
                    alert(response.data.message || "Failed to remove product from cart.");
                }
            })
            .catch(err => {
                console.error("Error removing from cart:", err);
                alert("An error occurred while removing product from cart.");
            });
    };

    const handlePlaceOrder = () => {
        const items = cart.map(item => ({
            productId: item.productId._id,
            quantity: item.quantity
        }));

       

        axios.post("http://localhost:3001/orders", { customerId, items })
            .then(response => {
                if (response.status === 201) {
                    alert("Order placed successfully!");
                    navigate('/my-orders'); // Navigate to orders page for confirmation
                } else {
                    alert(response.data.message || "Failed to place order.");
                }
            })
            .catch(err => {
                console.error("Error placing order:", err);
                alert(err.response?.data?.message || "An error occurred while placing your order.");
            });
    };

    return (
        <div className="container">
            <h2 className="row mt-3">Your Cart</h2>
            <div className="col col-12 col-sm-12 col-md-12 col-lg-12 col-xl-12 col-xxl-12">
                {cart.length > 0 ? cart.map((item) => (
                    item.productId && // Add a check to ensure productId is not null
                    <div key={item.productId._id} className="col col-12 col-sm-12 col-md-12 col-lg-12 col-xl-12 col-xxl-12">
                        <div className="card">
                            <div className="card-body">
                                <div className="row">
                                    <div className="col col-12 col-sm-12 col-md-12 col-lg-12 col-xl-12 col-xxl-12">
                                        <h5 className="card-title">{item.productId.name}</h5>
                                        <p className="card-text">{item.productId.description}</p>
                                        <h6 className="card-subtitle mb-2 text-muted">Price: ${item.productId.price}</h6>
                                    </div>
                                    <div className="col-md-3 d-flex align-items-center justify-content-center">
                                        <button className="btn btn-secondary btn-sm" onClick={() => handleDecrement(item.productId._id)}>-</button>
                                        <span className="mx-3">Quantity: {item.quantity}</span>
                                        <button className="btn btn-secondary btn-sm" onClick={() => handleIncrement(item.productId._id)}>+</button>
                                    </div>
                                    <div className="col-md-3 d-flex align-items-center justify-content-center">
                                        <h6>Subtotal: ${(item.productId.price * item.quantity).toFixed(2)}</h6>
                                    </div>
                                    <div className="col-md-2 d-flex align-items-center justify-content-center">
                                        <button className="btn btn-danger" onClick={() => handleRemoveFromCart(item.productId._id)}>Remove</button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )) : <div className="col"><p>Your cart is empty.</p></div>}
            </div>
            {cart.length > 0 && (
                <div className="row mt-4">
                    <div className="col text-end">
                        <h3>Total: ${totalPrice.toFixed(2)}</h3>
                        <button className="btn btn-success btn-lg" onClick={handlePlaceOrder}>Place Order</button>
                    </div>
                </div>
            )}
        </div>
    );
}

export default Cart
